    {'id': 'CALUS-PIA-SCAN-4468', 'name': 'activation-guided-mcmc-prompt-injection-tool', 'severity': 'low', 'category': 'prompt_injection_attacks', 'message': 'Activation-guided MCMC prompt injection framework detected. This implements a transferable black-box direct prompt injection attack using energy-based models and token-level MCMC sampling.', 'patterns': ['(?i)(?:from|import)\\s+energy_based_model\\s|class\\s+EnergyBasedModel\\s*\\(', '(?i)def\\s+get_activations\\s*\\(|activations\\s*=\\s*model\\.get_activations\\s*\\(', '(?i)def\\s+mcmc_sample\\s*\\(|token_level_mcmc|mcmc_sampling\\s*=', '(?i)energy_score\\s*=\\s*ebm\\.predict|ebm\\.score\\s*\\(|compute_energy\\s*\\(']},
    {'id': 'CALUS-PIA-SCAN-4469', 'name': 'prefix-infix-suffix-injection-template', 'severity': 'low', 'category': 'prompt_injection_attacks', 'message': 'Prefix-infix-suffix template combination detected. This is used to construct adversarial prompts for direct prompt injection attacks.', 'patterns': ['(?i)prefix\\s*\\+\\s*infix\\s*\\+\\s*suffix|prefix_list\\[.{0,40}\\]\\s*\\+\\s*infix_list\\[.{0,40}\\]|template_dataset\\s*=\\s*\\[.{0,40}prefix.{0,40}infix.{0,40}suffix', '(?i)combine_prefix_infix_suffix|generate_template\\s*\\(.{0,40}prefix.{0,40}infix.{0,40}suffix\\)', '(?i)random\\.choice\\(prefixes\\)\\s*\\+\\s*random\\.choice\\(infixes\\)']},
