    {'id': 'CALUS-PIA-SCAN-4471', 'name': 'mlp-activation-classifier-for-ebm', 'severity': 'medium', 'category': 'prompt_injection_attacks', 'message': 'Two-layer MLP activation classifier for energy-based model detected. This EBM is used to guide adversarial prompt generation.', 'patterns': ['(?i)class\\s+ActivationClassifier|nn\\.Linear\\(.{0,40}activation\\s*dim|self\\.fc1\\s*=\\s*nn\\.Linear', '(?i)def\\s+forward\\s*\\(self,\\s*activations|activations_to_energy|ebm_mlp_logits\\s*=', '(?i)train_ebm|train_activation_classifier|mse_loss_ebm|cross_entropy_ebm']},
