    {'id': 'CALUS-PIA-SCAN-4610', 'name': 'hijack-rag-malicious-text-composition', 'severity': 'medium', 'category': 'prompt_injection_attacks', 'message': 'Detected composition pattern of retrieval, hijack, and instruction text typical of HIJACK RAG malicious passage generation.', 'patterns': ['(?i)R\\s*⊕\\s*H\\s*⊕\\s*I|retrieval_text\\s*\\+\\s*hijack_text\\s*\\+\\s*instruction_text', '(?i)(?:retrieval|hijack|instruction)\\s*(?:text|prompt)\\s*(?:=|←|:)\\s*[\'"](?:print.{0,40}PWNED|ignore.{0,40}previous|output.{0,40}target)[\'"]']},
